mapper.select:
SELECT

FROM home_banner hb
LEFT JOIN city c ON c.id = hb.city_id AND c.region = hb.region
WHERE hb.id = #{id}
  AND hb.region = #{region}
LIMIT 1

SELECT COUNT(1)
FROM city
WHERE id = #{cityId}
  AND region = #{region}
  AND status = 1

mapper.update:
UPDATE home_banner
SET city_id = #{cityId},
    title = #{title},
    subtitle = #{subtitle},
    image_url = #{imageUrl},
    link_url = #{linkUrl},
    sort_no = #{sortNo}
WHERE id = #{id}
  AND region = #{region}

UPDATE home_banner
SET enabled = #{enabled}
WHERE id = #{id}
  AND region = #{region}

mapper.delete:
DELETE FROM home_banner
WHERE id = #{id}
  AND region = #{region}
